/// GET /v1/charges/search
/// Search charges
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `get_charges_search_execute()` to send, or `get_charges_search` for simplest API.

pub fn get_charges_search_builder<R>(
    client: &SimpleHttpClient<R>,
    expand: &Option<Option<String>>,
    limit: &Option<Option<String>>,
    page: &Option<Option<String>>,
    query: &Option<Option<String>>,
) -> Result<ClientRequestBuilder<R>, ApiError>
where
    R: DnsResolver + Clone,
{
    // Build URL
    let endpoint_url = format!("https://api.stripe.com//v1/charges/search",);

    // Build request
    let mut query_parts = Vec::new();
    if let Some(val) = expand.as_ref() {
        query_parts.push(format!("expand={}", val));
    }
    if let Some(val) = limit.as_ref() {
        query_parts.push(format!("limit={}", val));
    }
    if let Some(val) = page.as_ref() {
        query_parts.push(format!("page={}", val));
    }
    if let Some(val) = query.as_ref() {
        query_parts.push(format!("query={}", val));
    }

    let url_with_query = if query_parts.is_empty() {
        endpoint_url
    } else {
        format!("{}?{}", endpoint_url, query_parts.join("&"))
    };

    let builder = client
        .get(&url_with_query)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?;

    Ok(builder)
}

